CREATE DATABASE IF NOT EXISTS catalog_db;
USE catalog_db;
CREATE TABLE IF NOT EXISTS venues (
  venue_id INT PRIMARY KEY,
  name VARCHAR(160) NOT NULL,
  city VARCHAR(80),
  area VARCHAR(120),
  capacity INT,
  venue_type VARCHAR(60),
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  INDEX(city)
);
CREATE TABLE IF NOT EXISTS events (
  event_id INT PRIMARY KEY,
  venue_id INT NOT NULL,
  title VARCHAR(200) NOT NULL,
  event_type VARCHAR(60),
  city VARCHAR(80),
  status ENUM('ON_SALE','SOLD_OUT','CANCELLED') DEFAULT 'ON_SALE',
  start_time DATETIME,
  end_time DATETIME,
  base_price DECIMAL(10,2),
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  INDEX(city), INDEX(event_type), INDEX(status)
);
CREATE TABLE IF NOT EXISTS seat_definitions (
  seat_id INT PRIMARY KEY,
  event_id INT NOT NULL,
  seat_label VARCHAR(40) NOT NULL,
  section VARCHAR(40),
  seat_price DECIMAL(10,2),
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  INDEX(event_id)
);
